import Vision
import UIKit

let sequenceHandler = VNSequenceRequestHandler()
var lastObservation: VNDetectedObjectObservation?

func trackObject(pixelBuffer: CVPixelBuffer) {
    guard let observation = lastObservation else { return }

    let request = VNTrackObjectRequest(detectedObjectObservation: observation) { request, _ in
        if let result = request.results?.first as? VNDetectedObjectObservation {
            lastObservation = result
            print("🎯 Tracking Box: \(result.boundingBox)")
        }
    }

    try? sequenceHandler.perform([request], on: pixelBuffer)
}

import Vision
import UIKit

func detectHandPose(in image: UIImage) {
    guard let cgImage = image.cgImage else { return }

    let request = VNDetectHumanHandPoseRequest()
    request.maximumHandCount = 2

    let handler = VNImageRequestHandler(cgImage: cgImage)
    try? handler.perform([request])

    if let observations = request.results {
        for hand in observations {
            if let thumb = try? hand.recognizedPoints(.thumb)[.tip] {
                print("👍 Daumenspitze: \(thumb.location)")
            }
        }
    }
}

import Vision
