import Vision
import UIKit

func compareImages(_ img1: UIImage, _ img2: UIImage) {
    guard let cg1 = img1.cgImage, let cg2 = img2.cgImage else { return }

    let req1 = VNGenerateImageFeaturePrintRequest()
    let req2 = VNGenerateImageFeaturePrintRequest()

    let h1 = VNImageRequestHandler(cgImage: cg1)
    let h2 = VNImageRequestHandler(cgImage: cg2)

    try? h1.perform([req1])
    try? h2.perform([req2])

    if let fp1 = req1.results?.first as? VNFeaturePrintObservation,
       let fp2 = req2.results?.first as? VNFeaturePrintObservation {
        var distance: Float = 0
        try? fp1.computeDistance(&distance, to: fp2)
        print("🖼 Ähnlichkeit: \(distance)")
    }
}
